def grid_paths(n):
    dp = [[1] * (n + 1) for _ in range(n + 1)]
    for i in range(1, n + 1):
        for j in range(1, n + 1):
            dp[i][j] = dp[i-1][j] + dp[i][j-1]
    return dp[n][n]

print('2x2:', grid_paths(2))
print('20x20:', grid_paths(20))

